SELECT doc_id, MAX(notification_date) AS latest_notification_date
FROM document_notifications
WHERE doc_id = 1;

SELECT file_path
FROM document_files
WHERE file_type = 'PDF' AND upload_date >= '2023-01-01';

SELECT doc_name
FROM documents
ORDER BY doc_name ASC;

SELECT report_type
FROM document_reports
WHERE doc_id = 1;

SELECT COUNT(*) AS successful_migrations
FROM document_migrations
WHERE status = 'Success';

SELECT doc_id, MAX(comment_date) AS last_comment_date
FROM document_comments
GROUP BY doc_id;

SELECT tag_name 
FROM document_tags 
WHERE doc_id = 1;

SELECT MAX(version_number) AS latest_version
FROM document_versions
WHERE doc_id = 1;
